import React, { useState } from "react";

const API_BASE = "http://localhost:8000";

// hidden defaults (not shown in UI)
const DEFAULTS = {
  axis: 0.1,
  speed: 60,
  steering_angle: 5,
};

// status colors
const STATUS_THEME = {
  safe: {
    bg: "#e8f5e9",
    border: "#43a047",
    text: "#1b5e20",
    label: "SAFE",
    emoji: "✅",
  },
  warning: {
    bg: "#fffde7",
    border: "#fdd835",
    text: "#7c5000",
    label: "WARNING",
    emoji: "⚠️",
  },
  danger: {
    bg: "#ffebee",
    border: "#e53935",
    text: "#7f0000",
    label: "DANGER",
    emoji: "🚨",
  },
};

const initialForm = {
  distance: "",
  ttc: "",
  relative_velocity: "",
};

function App() {
  const [form, setForm] = useState(initialForm);
  const [result, setResult] = useState(null);
  const [submittedData, setSubmittedData] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setError(null);
  };

  const resetForm = () => {
    setForm(initialForm);
    setResult(null);
    setError(null);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setResult(null);

    // simple validation
    if (!form.distance || !form.ttc || !form.relative_velocity) {
      setError("Please fill in all fields.");
      setLoading(false);
      return;
    }

    const payload = {
      distance: parseFloat(form.distance),
      ttc: parseFloat(form.ttc),
      relative_velocity: parseFloat(form.relative_velocity),
      ...DEFAULTS,
    };

    try {
      const res = await fetch(`${API_BASE}/predict`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      if (!res.ok) {
        throw new Error("Prediction failed.");
      }

      const data = await res.json();
      setResult(data);
      setSubmittedData(payload);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const theme =
    result && STATUS_THEME[result.predicted_status]
      ? STATUS_THEME[result.predicted_status]
      : null;

  return (
    <div style={styles.page}>
      <header style={styles.header}>
        <h1>Vehicle Safety Prediction</h1>
        <p>Real-time risk check using sensor values</p>
      </header>

      <main style={styles.container}>
        {/* Input section */}
        <div style={styles.card}>
          <h2>Enter Sensor Data</h2>

          <form onSubmit={handleSubmit}>
            <div style={styles.field}>
              <label>Distance (m)</label>
              <input
                type="number"
                name="distance"
                value={form.distance}
                onChange={handleChange}
                placeholder="e.g. 25"
              />
            </div>

            <div style={styles.field}>
              <label>Time-to-Collision (s)</label>
              <input
                type="number"
                name="ttc"
                value={form.ttc}
                onChange={handleChange}
                placeholder="e.g. 3.5"
              />
            </div>

            <div style={styles.field}>
              <label>Relative Velocity (m/s)</label>
              <input
                type="number"
                name="relative_velocity"
                value={form.relative_velocity}
                onChange={handleChange}
                placeholder="e.g. -12"
              />
            </div>

            {error && <div style={styles.error}>{error}</div>}

            <div style={styles.buttons}>
              <button type="submit" disabled={loading}>
                {loading ? "Analysing..." : "Predict"}
              </button>
              <button type="button" onClick={resetForm}>
                Reset
              </button>
            </div>
          </form>
        </div>

        {/* Result section */}
        <div style={styles.card}>
          <h2>Prediction Result</h2>

          {!result && !loading && (
            <p style={{ color: "#888" }}>
              Submit values to see prediction.
            </p>
          )}

          {loading && <p>Processing...</p>}

          {result && theme && (
            <div
              style={{
                background: theme.bg,
                border: `2px solid ${theme.border}`,
                padding: "20px",
                borderRadius: "8px",
              }}
            >
              <h3 style={{ color: theme.text }}>
                {theme.emoji} {theme.label}
              </h3>
              <p>{result.message}</p>
            </div>
          )}

          {submittedData && (
            <div style={{ marginTop: "15px", fontSize: "13px" }}>
              <strong>Submitted values:</strong>
              <div>Distance: {submittedData.distance} m</div>
              <div>TTC: {submittedData.ttc} s</div>
              <div>Relative Velocity: {submittedData.relative_velocity} m/s</div>
            </div>
          )}
        </div>
      </main>

      <footer style={styles.footer}>
        FastAPI + React + SQLite ML Demo
      </footer>
    </div>
  );
}

const styles = {
  page: {
    fontFamily: "Arial, sans-serif",
    background: "#f4f6fb",
    minHeight: "100vh",
  },
  header: {
    background: "#1B2B4B",
    color: "#fff",
    padding: "20px",
    textAlign: "center",
  },
  container: {
    display: "flex",
    gap: "20px",
    padding: "30px",
    flexWrap: "wrap",
  },
  card: {
    flex: 1,
    minWidth: "300px",
    background: "#fff",
    padding: "20px",
    borderRadius: "8px",
    boxShadow: "0 2px 10px rgba(0,0,0,0.08)",
  },
  field: {
    marginBottom: "15px",
    display: "flex",
    flexDirection: "column",
  },
  buttons: {
    display: "flex",
    gap: "10px",
  },
  error: {
    color: "red",
    marginBottom: "10px",
  },
  footer: {
    textAlign: "center",
    padding: "10px",
    color: "#777",
    fontSize: "12px",
  },
};

export default App;
